app = FastAPI(title="Community-Driven AI Training Pipeline", version="1.0.0")

train_lock = threading.Lock()


def _now():
    return datetime.utcnow().isoformat() + "Z"


def _load_meta() -> Dict[str, Any]:
    if not os.path.exists(META_PATH):
        return {
            "datasets": [],
            "contributions": [],
            "models": [],
            "current_model_path": None,
            "last_trained_at": None,
        }
    with open(META_PATH, "r", encoding="utf-8") as f:
        return json.load(f)


def _save_meta(meta: Dict[str, Any]) -> None:
    os.makedirs(BASE_DIR, exist_ok=True)
    with open(META_PATH, "w", encoding="utf-8") as f:
        json.dump(meta, f, indent=2)


def _append_metadata(collection: str, record: Dict[str, Any]) -> None:
    meta = _load_meta()
    meta.setdefault(collection, [])
    meta[collection].append(record)
    _save_meta(meta)


def _store_upload(file: UploadFile, target_dir: str, prefix: str) -> str:
    ext = os.path.splitext(file.filename or "")[1].lower()
    safe_name = f"{prefix}_{uuid.uuid4().hex}{ext}"
    path = os.path.join(target_dir, safe_name)
    with open(path, "wb") as f:
        shutil.copyfileobj(file.file, f)
    return path


def _ensure_label_column(df: pd.DataFrame, label_col: str) -> None:
    if label_col not in df.columns:
        raise HTTPException(status_code=400, detail=f"CSV must contain label column '{label_col}'")


def _encode_labels(labels: List[Any]):
    unique_labels = sorted(list({str(x) for x in labels}))
    label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
    idx_to_label = {idx: label for label, idx in label_to_idx.items()}
    y = np.array([label_to_idx[str(x)] for x in labels], dtype=np.int32)
    return y, label_to_idx, idx_to_label


def _build_csv_model(input_dim: int, num_classes: int) -> tf.keras.Model:
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(input_dim,)),
        tf.keras.layers.Normalization(),
        tf.keras.layers.Dense(128, activation="relu"),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(64, activation="relu"),
        tf.keras.layers.Dropout(0.2),
        tf.keras.layers.Dense(num_classes, activation="softmax"),
    ])
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


def _preprocess_image(path: str, image_size=(224, 224)):
    image = tf.io.read_file(path)
    image = tf.image.decode_image(image, channels=3, expand_animations=False)
    image = tf.image.resize(image, image_size)
    image = tf.cast(image, tf.float32) / 255.0
    return image


def _load_image_dataset(image_dir: str, image_size=(224, 224), batch_size=32):
    ds = tf.keras.utils.image_dataset_from_directory(
        image_dir,
        labels="inferred",
        label_mode="int",
        image_size=image_size,
        batch_size=batch_size,
        shuffle=True,
    )
    class_names = ds.class_names
    ds = ds.map(lambda x, y: (tf.cast(x, tf.float32) / 255.0, y))
    return ds, class_names


def _build_image_model(num_classes: int, image_size=(224, 224)) -> tf.keras.Model:
    base = tf.keras.applications.MobileNetV2(
        include_top=False,
        weights="imagenet",
        input_shape=(image_size[0], image_size[1], 3),
    )
    base.trainable = False

    inputs = tf.keras.Input(shape=(image_size[0], image_size[1], 3))
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs * 255.0)
    x = base(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)

    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model


class CSVTrainRequest(BaseModel):
    label_column: str = Field(default="label")
    epochs: int = Field(default=5, ge=1, le=100)
    batch_size: int = Field(default=32, ge=1, le=1024)
    validation_split: float = Field(default=0.2, ge=0.0, le=0.9)


class ImageTrainRequest(BaseModel):
    epochs: int = Field(default=5, ge=1, le=100)
    batch_size: int = Field(default=32, ge=1, le=256)
    image_size: int = Field(default=224, ge=64, le=512)
    validation_split: float = Field(default=0.2, ge=0.0, le=0.9)


class ContributionRequest(BaseModel):
    contributor_id: Optional[str] = None
    label: str
    metadata: Optional[Dict[str, Any]] = None


