@app.post("/train/csv")
async def train_csv(
    request: CSVTrainRequest,
    file: UploadFile = File(...),
):
    if not file.filename or not file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="Only CSV files are supported")
    if train_lock.locked():
        raise HTTPException(status_code=409, detail="Training already in progress")
    with train_lock:
        path = _store_upload(file, CSV_DIR, "train_csv")
        df = pd.read_csv(path)
        _ensure_label_column(df, request.label_column)
        df = df.dropna()
        y, label_to_idx, idx_to_label = _encode_labels(df[request.label_column].tolist())
        X = df.drop(columns=[request.label_column]).select_dtypes(include=[np.number]).values.astype(np.float32)
        if X.size == 0:
            raise HTTPException(status_code=400, detail="CSV must contain numeric feature columns")
        if len(X) != len(y):
            raise HTTPException(status_code=400, detail="Feature and label rows mismatch")

        n = len(X)
        idx = np.arange(n)
        np.random.shuffle(idx)
        split = int(n * (1.0 - request.validation_split))
        train_idx, val_idx = idx[:split], idx[split:]
        X_train, X_val = X[train_idx], X[val_idx]
        y_train, y_val = y[train_idx], y[val_idx]

        model = _build_csv_model(X.shape[1], len(label_to_idx))
        norm_layer = model.layers[0].layers[0]
        norm_layer.adapt(X_train)

        callbacks = [
            tf.keras.callbacks.EarlyStopping(patience=3, restore_best_weights=True),
        ]
        history = model.fit(
            X_train,
            y_train,
            validation_data=(X_val, y_val) if len(X_val) else None,
            epochs=request.epochs,
            batch_size=request.batch_size,
            callbacks=callbacks,
            verbose=0,
        )

        model_id = uuid.uuid4().hex
        model_path = os.path.join(MODEL_DIR, f"csv_model_{model_id}")
        model.save(model_path)

        meta = _load_meta()
        meta["current_model_path"] = model_path
        meta["last_trained_at"] = _now()
        meta.setdefault("models", []).append({
            "id": model_id,
            "type": "csv",
            "path": model_path,
            "trained_at": meta["last_trained_at"],
            "metrics": {k: float(v[-1]) for k, v in history.history.items()},
            "label_to_idx": label_to_idx,
            "idx_to_label": idx_to_label,
            "feature_count": int(X.shape[1]),
        })
        _save_meta(meta)

        return {
            "message": "CSV model trained",
            "model_id": model_id,
            "model_path": model_path,
            "metrics": {k: float(v[-1]) for k, v in history.history.items()},
            "labels": list(label_to_idx.keys()),
        }


@app.post("/train/image")
async def train_image(request: ImageTrainRequest):
    if train_lock.locked():
        raise HTTPException(status_code=409, detail="Training already in progress")
    with train_lock:
        image_size = (request.image_size, request.image_size)
        ds, class_names = _load_image_dataset(IMG_DIR, image_size=image_size, batch_size=request.batch_size)
        if len(class_names) < 2:
            raise HTTPException(status_code=400, detail="Need at least two image classes for training")

        total_batches = tf.data.experimental.cardinality(ds).numpy()
        if total_batches <= 0:
            raise HTTPException(status_code=400, detail="No image data found")

        val_batches = max(1, int(total_batches * request.validation_split))
        train_ds = ds.skip(val_batches)
        val_ds = ds.take(val_batches)

        autotune = tf.data.AUTOTUNE
        train_ds = train_ds.prefetch(buffer_size=autotune)
        val_ds = val_ds.prefetch(buffer_size=autotune)

        model = _build_image_model(len(class_names), image_size=image_size)
        callbacks = [
            tf.keras.callbacks.EarlyStopping(patience=3, restore_best_weights=True),
        ]
        history = model.fit(
            train_ds,
            validation_data=val_ds,
            epochs=request.epochs,
            callbacks=callbacks,
            verbose=0,
        )

        model_id = uuid.uuid4().hex
        model_path = os.path.join(MODEL_DIR, f"image_model_{model_id}")
        model.save(model_path)

        meta = _load_meta()
        meta["current_model_path"] = model_path
        meta["last_trained_at"] = _now()
        meta.setdefault("models", []).append({
            "id": model_id,
            "type": "image",
            "path": model_path,
            "trained_at": meta["last_trained_at"],
            "metrics": {k: float(v[-1]) for k, v in history.history.items()},
            "class_names": class_names,
            "image_size": request.image_size,
        })
        _save_meta(meta)

        return {
            "message": "Image model trained",
            "model_id": model_id,
            "model_path": model_path,
            "metrics": {k: float(v[-1]) for k, v in history.history.items()},
            "classes": class_names,
        }


@app.post("/predict/image")
async def predict_image(file: UploadFile = File(...)):
    meta = _load_meta()
    model_path = meta.get("current_model_path")
    if not model_path or not os.path.exists(model_path):
        raise HTTPException(status_code=404, detail="No trained model available")
    if not file.filename:
        raise HTTPException(status_code=400, detail="Missing file")
    image_bytes = await file.read()
    image = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    image = image.resize((224, 224))
    arr = np.array(image).astype(np.float32) / 255.0
    arr = np.expand_dims(arr, axis=0)

    model = tf.keras.models.load_model(model_path)
    preds = model.predict(arr, verbose=0)[0].tolist()
    model_info = None
    for m in reversed(meta.get("models", [])):
        if m.get("path") == model_path:
            model_info = m
            break

    classes = model_info.get("class_names") if model_info else None
    if classes:
        result = [{"label": classes[i], "score": float(preds[i])} for i in range(len(preds))]
    else:
        result = [{"class_index": i, "score": float(preds[i])} for i in range(len(preds))]
    result = sorted(result, key=lambda x: x["score"], reverse=True)

    return {"predictions": result[:5], "model_path": model_path}


@app.post("/retrain")
async def retrain():
    meta = _load_meta()
    if train_lock.locked():
        raise HTTPException(status_code=409, detail="Training already in progress")
    with train_lock:
        image_dirs = [d for d in os.listdir(IMG_DIR) if os.path.isdir(os.path.join(IMG_DIR, d))]
        csv_files = [r["path"] for r in meta.get("datasets", []) if r.get("type") == "csv" and os.path.exists(r.get("path", ""))]
        results = {}

        if image_dirs:
            try:
                ds, class_names = _load_image_dataset(IMG_DIR, image_size=(224, 224), batch_size=32)
                val_batches = max(1, int(tf.data.experimental.cardinality(ds).numpy() * 0.2))
                train_ds = ds.skip(val_batches).prefetch(tf.data.AUTOTUNE)
                val_ds = ds.take(val_batches).prefetch(tf.data.AUTOTUNE)
                model = _build_image_model(len(class_names), image_size=(224, 224))
                history = model.fit(train_ds, validation_data=val_ds, epochs=3, verbose=0)
                model_id = uuid.uuid4().hex
                model_path = os.path.join(MODEL_DIR, f"image_model_{model_id}")
                model.save(model_path)
                meta["current_model_path"] = model_path
                meta["last_trained_at"] = _now()
                meta.setdefault("models", []).append({
                    "id": model_id,
                    "type": "image",
                    "path": model_path,
                    "trained_at": meta["last_trained_at"],
                    "metrics": {k: float(v[-1]) for k, v in history.history.items()},
                    "class_names": class_names,
                    "image_size": 224,
                })
                results["image"] = {"model_path": model_path, "metrics": {k: float(v[-1]) for k, v in history.history.items()}}
            except Exception as e:
                results["image_error"] = str(e)

        if csv_files:
            try:
                path = csv_files[-1]
                df = pd.read_csv(path).dropna()
                label_col = "label" if "label" in df.columns else None
                if not label_col:
                    raise ValueError("No label column in CSV dataset")
                y, label_to_idx, idx_to_label = _encode_labels(df[label_col].tolist())
                X = df.drop(columns=[label_col]).select_dtypes(include=[np.number]).values.astype(np.float32)
                model = _build_csv_model(X.shape[1], len(label_to_idx))
                model.layers[0].layers[0].adapt(X)
                history = model.fit(X, y, epochs=3, batch_size=32, verbose=0)
                model_id = uuid.uuid4().hex
                model_path = os.path.join(MODEL_DIR, f"csv_model_{model_id}")
                model.save(model_path)
                meta["current_model_path"] = model_path
                meta["last_trained_at"] = _now()
                meta.setdefault("models", []).append({
                    "id": model_id,
                    "type": "csv",
                    "path": model_path,
                    "trained_at": meta["last_trained_at"],
                    "metrics": {k: float(v[-1]) for k, v in history.history.items()},
                    "label_to_idx": label_to_idx,
                    "idx_to_label": idx_to_label,
                    "feature_count": int(X.shape[1]),
                })
                results["csv"] = {"model_path": model_path, "metrics": {k: float(v[-1]) for k, v in history.history.items()}}
            except Exception as e:
                results["csv_error"] = str(e)

        _save_meta(meta)
        return {"message": "Retraining completed", "results": results, "last_trained_at": meta.get("last_trained_at")}


